document.addEventListener('DOMContentLoaded', function() {
    let i = 0;
    const p = document.getElementById('fireworks');
    if (p) {
        setInterval(() => {
            p.innerText = frames[i];
            i = (i + 1) % frames.length;
        }, 83);
    } else {
        console.error('Element with id "fireworks" not found');
    }
});
